const items = [];

for (const item of $input.all()) {
  const responseText = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parsed = {
      document_type: 'unknown',
      confidence: 0,
      extracted_data: { error: 'Failed to parse', raw_response: responseText.substring(0, 500) }
    };
  }

  // Flag low confidence as unknown
  if (parsed.confidence < 0.7) {
    parsed.document_type = 'unknown';
  }

  items.push({
    json: {
      documentType: parsed.document_type,
      confidence: parsed.confidence,
      extractedData: parsed.extracted_data,
      processedAt: new Date().toISOString(),
    }
  });
}

return items;

const items = [];

for (const item of $input.all()) {
  const extractedText = (item.json.text || item.json.data || '').substring(0, 6000);

  // Escape the text so it's safe inside JSON
  const safeText = extractedText
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/\t/g, '\\t');

  const prompt = `You are an AI document processor for Apex Accounting, a CPA firm.

STEP 1 - CLASSIFY this document into exactly ONE type:
- vendor_invoice (invoice from a vendor billing for products/services)
- receipt (proof of payment for an expense)
- onboarding_form (new client intake form)
- financial_statement (P&L, balance sheet, income statement)

STEP 2 - EXTRACT all relevant structured data based on the document type.

For vendor_invoice extract: vendor_name, vendor_address, vendor_email, vendor_phone, invoice_number, invoice_date, due_date, payment_terms, bill_to_name, bill_to_address, line_items (array of {description, quantity, unit_price, amount}), subtotal, tax_amount, tax_rate, shipping, total_due, payment_instructions

For receipt extract: merchant_name, merchant_address, merchant_phone, receipt_date, receipt_number, line_items (array of {description, amount}), subtotal, tax_amount, tip, total, payment_method, business_purpose, attendees

For onboarding_form extract: business_name, dba_name, business_type, industry, ein_tax_id, state_of_formation, date_of_formation, fiscal_year_end, contact_name, contact_title, contact_email, contact_phone, contact_address, services_requested (array), estimated_monthly_fee

For financial_statement extract: company_name, statement_type, period_ending, prepared_by, prepared_date, total_revenue, total_expenses, net_income, revenue_breakdown (array of {category, amount}), expense_breakdown (array of {category, amount}), notes

Respond with ONLY a valid JSON object in this format, nothing else:
{
  "document_type": "<type>",
  "confidence": <0.0-1.0>,
  "extracted_data": { ... all fields for this document type ... }
}

If a field is missing or unclear, set it to null. Never guess.

--- DOCUMENT TEXT ---
${safeText}`;

  items.push({
    json: {
      prompt: prompt,
      extractedText: extractedText,
      senderEmail: item.json.from?.value?.[0]?.address || item.json.from || '',
      senderName: item.json.from?.value?.[0]?.name || '',
      emailSubject: item.json.subject || '',
      fileName: item.json.attachments?.[0]?.filename || '',
    }
  });
}

return items;

