const data = $('Switch').first().json.extractedData;
const email = data.contact_email;
const name = data.contact_name;
const company = data.business_name;
const fee = data.estimated_monthly_fee || '$0';
const services = data.services_requested || [];

// Parse the monthly fee as a number
const totalFee = parseFloat(fee.replace(/[^0-9.]/g, '')) || 0;

// Create a row for each service, splitting the fee roughly
const perServiceFee = services.length > 0 ? totalFee / services.length : totalFee;

const items = services.map(service => ({
  json: {
    clientEmail: email,
    clientName: name,
    company: company,
    serviceDescription: service,
    quantity: '1',
    rate: perServiceFee.toFixed(2),
    amount: perServiceFee.toFixed(2),
    status: 'Active'
  }
}));

// If no services parsed, create one generic row
if (items.length === 0) {
  items.push({
    json: {
      clientEmail: email,
      clientName: name,
      company: company,
      serviceDescription: 'Accounting Services',
      quantity: '1',
      rate: totalFee.toFixed(2),
      amount: totalFee.toFixed(2),
      status: 'Active'
    }
  });
}

return items;
